313	func TestExecuteBead_ThirdLevelDecompositionGetsRejectedWithExplanation(t *testing.T) {
314		root := t.TempDir()
315		wt := t.TempDir()
316		ddxDir := filepath.Join(root, ".ddx")
317		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
318			t.Fatal(err)
319		}
320		store := bead.NewStore(ddxDir)
321		if err := store.Init(); err != nil {
322			t.Fatal(err)
323		}
324	
325		rootBead := &bead.Bead{
326			ID:    "ddx-root",
327			Title: "Root bead",
328		}
329		childBead := &bead.Bead{
330			ID:     "ddx-child",
331			Title:  "Child bead",
332			Parent: rootBead.ID,
333		}
334		grandchildBead := &bead.Bead{
335			ID:     "ddx-grandchild",
336			Title:  "Grandchild bead",
337			Parent: childBead.ID,
338		}
339		for _, b := range []*bead.Bead{rootBead, childBead, grandchildBead} {
340			if err := store.Create(b); err != nil {
341				t.Fatalf("store.Create(%s): %v", b.ID, err)
342			}
343		}
344	
345		arts, err := createArtifactBundle(root, wt, "20260101T000000-depth0001")
346		if err != nil {
347			t.Fatalf("createArtifactBundle: %v", err)
348		}
349	
350		cases := []struct {
351			name    string
352			bead    *bead.Bead
353			wantCap bool
354		}{
355			{name: "root", bead: rootBead, wantCap: false},
356			{name: "child", bead: childBead, wantCap: false},
357			{name: "grandchild", bead: grandchildBead, wantCap: true},
358		}
359	
360		for _, tc := range cases {
361			tc := tc
362			t.Run(tc.name, func(t *testing.T) {
363				prompt, _, err := buildPrompt(root, tc.bead, nil, arts, "1234abcd", "", "claude", "")
364				if err != nil {
365					t.Fatalf("buildPrompt: %v", err)
366				}
367				s := string(prompt)
368				gotCap := strings.Contains(s, "Decomposition depth cap")
369				if gotCap != tc.wantCap {
370					t.Fatalf("cap hint presence = %v, want %v; prompt=%s", gotCap, tc.wantCap, s)
371				}
372				if tc.wantCap {
373					if !strings.Contains(s, "already at decomposition depth 2") {
374						t.Fatalf("grandchild prompt missing explicit depth explanation: %s", s)
375					}
376					if !strings.Contains(s, "reject the split") {
377						t.Fatalf("grandchild prompt missing rejection guidance: %s", s)
378					}
379					if !strings.Contains(s, "no_changes_rationale.txt") {
380						t.Fatalf("grandchild prompt missing no_changes rationale guidance: %s", s)
381					}
382				}
383			})
384		}
385	}
